<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --ubuntu-orange: #E95420;
            --ubuntu-purple: #300a24;
            --window-bg: #3d3d3d;
            --header-bg: #444;
            --text-color: #eeeeee;
            --taskbar-bg: rgba(0, 0, 0, 0.6);
        }

        * { box-sizing: border-box; }

        body, html {
            margin: 0;
            padding: 0;
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-serif, Arial, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #300a24 0%, #000000 100%);
            position: relative;
            overflow: hidden;
            user-select: none;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 15px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--taskbar-bg);
            padding: 8px 20px;
            border-radius: 30px;
            display: flex;
            gap: 15px;
            backdrop-filter: blur(10px);
            z-index: 1000;
            border: 1px solid rgba(255, 255, 255, 0.1);
        }

        #taskbar button {
            background: rgba(255, 255, 255, 0.1);
            border: none;
            color: white;
            padding: 8px 15px;
            border-radius: 15px;
            cursor: pointer;
            font-size: 14px;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: var(--ubuntu-orange);
        }

        /* Window Styles */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 15px 35px rgba(0, 0, 0, 0.5);
            display: none; /* Controlled by JS */
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #555;
            z-index: 10;
        }

        .win-header {
            background: var(--header-bg);
            padding: 10px 15px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            border-bottom: 1px solid #222;
        }

        .win-title {
            color: var(--text-color);
            font-weight: bold;
            font-size: 14px;
        }

        .win-close {
            background: transparent;
            border: none;
            color: #ff5f56;
            font-size: 20px;
            cursor: pointer;
            line-height: 1;
        }

        .win-close:hover {
            color: #ff3b30;
        }

        /* Files App Specifics */
        #files-toolbar {
            padding: 5px 10px;
            background: #4a4a4a;
            display: flex;
            align-items: center;
            gap: 10px;
            border-bottom: 1px solid #222;
        }

        #files-up {
            background: #666;
            border: none;
            color: white;
            padding: 3px 8px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 12px;
        }

        #files-path {
            color: #ccc;
            font-size: 13px;
            font-family: monospace;
        }

        #files-list {
            flex: 1;
            overflow-y: auto;
            padding: 10px;
            display: flex;
            flex-direction: column;
            gap: 2px;
        }

        .fs-item {
            color: #eee;
            padding: 6px 10px;
            cursor: pointer;
            border-radius: 4px;
            font-size: 14px;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .fs-item:hover {
            background: rgba(255, 255, 255, 0.1);
        }

        /* Notepad App Specifics */
        #tabs {
            display: flex;
            background: #222;
            overflow-x: auto;
            scrollbar-width: none;
        }

        .tab {
            padding: 8px 15px;
            color: #aaa;
            cursor: pointer;
            border: none;
            background: transparent;
            font-size: 13px;
            white-space: nowrap;
            transition: background 0.2s, color 0.2s;
        }

        .tab.active {
            background: var(--window-bg);
            color: white;
            border-bottom: 2px solid var(--ubuntu-orange);
        }

        #new-tab {
            padding: 8px 12px;
            background: transparent;
            border: none;
            color: white;
            cursor: pointer;
            font-size: 18px;
        }

        #editor {
            flex: 1;
            width: 100%;
            border: none;
            background: #222;
            color: #eee;
            padding: 15px;
            resize: none;
            outline: none;
            font-family: 'Courier New', monospace;
            font-size: 14px;
            line-height: 1.5;
        }

        #notepad-toolbar {
            display: flex;
            background: #333;
            border-bottom: 1px solid #222;
        }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="win-header">
            <span class="win-title">Files</span>
            <button class="win-close">&times;</button>
        </div>
        <div id="files-toolbar">
            <button id="files-up">Up</button>
            <div id="files-path">/</div>
        </div>
        <div id="files-list">
            <!-- Items injected by JS -->
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="win-header">
            <span class="win-title">Notepad</span>
            <button class="win-close">&times;</button>
        </div>
        <div id="notepad-toolbar">
            <div id="tabs"></div>
            <button id="new-tab">+</button>
        </div>
        <textarea id="editor" spellcheck="false"></textarea>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>
</div>

<script>
    /** 1. FILESYSTEM DATA **/
    const fsData = {
        '/': ['bin', 'etc', 'home', 'usr', 'var'],
        '/bin': [],
        '/etc': [],
        '/home': ['user'],
        '/home/user': ['Documents', 'Downloads', 'Pictures', 'notes.txt'],
        '/home/user/Documents': [],
        '/home/user/Downloads': [],
        '/home/user/Pictures': [],
        '/usr': ['local'],
        '/usr/local': [],
        '/var': ['log'],
        '/var/log': []
    };

    let currentPath = '/';

    /** 2. NOTEPAD STATE & PERSISTENCE **/
    let notepadState = {
        activeTabId: null,
        tabs: []
    };

    function loadNotepad() {
        const saved = localStorage.getItem('ubuntu_notepad_data');
        if (saved) {
            notepadState = JSON.parse(saved);
        } else {
            const initialId = Date.now();
            notepadState.tabs = [{ id: initialId, title: 'Untitled', content: '' }];
            notepadumentState.activeTabId = initialId;
        }
    }

    function saveNotepad() {
        localStorage.setItem('ubuntu_notepad_data', JSON.stringify(notepadState));
    }

    /** 3. WINDOW MANAGEMENT **/
    function setupWindowDraggable(win) {
        const header = win.querySelector('.win-header');
        let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;

        header.onmousedown = (e) => {
            e.preventDefault();
            pos3 = e.clientX;
            pos4 = e.clientY;
            document.onmouseup = () => {
                document.onmouseup = null;
                document.onmousemove = null;
            };
            document.onmousemove = (e) => {
                e.preventDefault();
                pos1 = pos3 - e.clientX;
                pos2 = pos4 - e.clientY;
                pos3 = e.clientX;
                pos4 = e.clientY;
                win.style.top = (win.offsetTop - pos2) + "px";
                win.style.left = (win.offsetLeft - pos1) + "px";
            };
            // Bring to front
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 20;
        };
    }

    function attachCloseButtons() {
        document.querySelectorAll('.win-close').forEach(btn => {
            btn.onclick = () => {
                btn.closest('.window').style.display = 'none';
            };
        });
    }

    /** 4. FILES APP LOGIC **/
    function renderFiles() {
        const list = document.getElementById('files-list');
        const pathDisplay = document.getElementById('files-path');
        list.innerHTML = '';
        pathDisplay.textContent = currentPath;

        const items = fsData[currentPath] || [];
        items.forEach(name => {
            const item = document.createElement('div');
            item.className = 'fs-item';
            item.textContent = name;
            item.ondblclick = () => {
                const newPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
                if (fsData[newPath] !== undefined) {
                    currentPath = newPath;
                    renderFiles();
                }
            };
            list.appendChild(item);
        });
    }

    document.getElementById('files-up').onclick = () => {
        if (currentPath === '/') return;
        const parts = currentPath.split('/').filter(p => p);
        parts.pop();
        currentPath = '/' + parts.join('/');
        renderFiles();
    };

    /** 5. NOTEPAD APP LOGIC **/
    const editor = document.getElementById('editor');
    const tabsContainer = document.getElementById('tabs');

    function renderTabs() {
        tabsContainer.innerHTML = '';
        notepadState.tabs.forEach(tab => {
            const tabEl = document.createElement('button');
            tabEl.className = 'tab' + (tab.id === notepadState.activeTabId ? ' active' : '');
            tabEl.textContent = tab.title;
            tabEl.onclick = () => switchTab(tab.id);
            tabsContainer.appendChild(tabEl);
        });
    }

    function switchTab(id) {
        notepadState.activeTabId = id;
        const activeTab = notepadState.tabs.find(t => t.id === id);
        if (activeTab) {
            editor.value = activeTab.content;
        }
        renderTabs();
        saveNotepad();
    }

    function createNewTab() {
        const newId = Date.now();
        notepadState.tabs.push({ id: newId, title: 'Untitled', content: '' });
        notepadState.activeTabId = newCD_id = newId;
        renderTabs();
        switchTab(newId);
        saveNotepad();
    }

    editor.oninput = () => {
        const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeTabId);
        if (activeTab) {
            activeTab.content = editor.value;
            saveNotepad();
        }
    };

    document.getElementById('new-tab').onclick = createNewTab;

    /** 6. INITIALIZATION **/
    window.onload = () => {
        // Init Files
        renderFiles();

        // Init Notepad
        loadNotepad();
        if (notepadState.tabs.length > 0) {
            switchTab(notepadState.activeTabId);
        } else {
            createNewTab();
        }

        // Taskbar Listeners
        document.getElementById('open-files').onclick = () => {
            const win = document.getElementById('files-window');
            win.style.display = 'flex';
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 20;
        };

        document.getElementById('open-notepad').onclick = () => {
            const win = document.getElementById('notepad-window');
            win.style.display = 'flex';
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 20;
        };

        // Setup Windows
        document.querySelectorAll('.window').forEach(setupWindowDraggable);
        attachCloseButtons();
    };
</script>

</body>
</html>
